    public static function byProvinsi(string $idProv): array
    {
        return collect(self::$daerah)
            ->where('id_prov', $idProv)
            ->pluck('daerah', 'id_daerah')
            ->toArray();
    }

    public static function all()
    {
        return collect(self::$daerah)
            ->pluck('daerah', 'id_daerah')
            ->toArray();
    }
